## Implementation Plan: JWT Authentication

### Overview

Six files need to change. Two are new (`src/middleware/auth.ts`, `src/routes/auth.ts`), four are modifications (`src/types.ts`, `src/app.ts`, `src/routes/posts.ts`, `src/routes/comments.ts`). The order below respects dependencies: types first, then middleware, then routes, then app registration.

---

### Step 1 — `src/types.ts` (modify)

Append a `JwtPayload` interface to the existing file. Nothing else in the file changes.

```ts
export interface JwtPayload {
  userId: number;
  username: string;
}
```

This interface is the shared contract between the token-signing code in `src/routes/auth.ts` and the token-verifying code in `src/middleware/auth.ts`. It is defined here rather than inside the middleware so that the auth route can import it without creating a circular dependency.

---

### Step 2 — `src/middleware/auth.ts` (create new file)

This file has two responsibilities: augmenting the Express `Request` type and exporting the `authenticate` middleware function.

```ts
import { Request, Response, NextFunction } from "express";
import jwt from "jsonwebtoken";
import { JwtPayload } from "../types.js";

// Module-level type augmentation. The file must be a module (has imports),
// so the `declare global` block correctly patches the Express namespace.
declare global {
  namespace Express {
    interface Request {
      user?: JwtPayload;
    }
  }
}

const JWT_SECRET = "super-secret-key";

export { JWT_SECRET };

export function authenticate(
  req: Request,
  res: Response,
  next: NextFunction
): void {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    res.status(401).json({ error: "No token provided" });
    return;
  }

  const token = authHeader.slice(7); // strip "Bearer "
  try {
    const payload = jwt.verify(token, JWT_SECRET) as JwtPayload;
    req.user = payload;
    next();
  } catch {
    res.status(401).json({ error: "Invalid or expired token" });
  }
}
```

Key decisions:
- `JWT_SECRET` is exported so `src/routes/auth.ts` can import it from one place rather than duplicating the string literal.
- The cast `as JwtPayload` is required because `jwt.verify` returns `string | JwtPayload` in the `@types/jsonwebtoken` typings when called with two arguments.
- The `declare global` block works because the file has `import` statements at the top, making it a module rather than a script.

---

### Step 3 — `src/routes/auth.ts` (create new file)

```ts
import { Router } from "express";
import jwt from "jsonwebtoken";
import { users, nextId } from "../db.js";
import { JwtPayload } from "../types.js";
import { JWT_SECRET } from "../middleware/auth.js";

const router = Router();

// POST /auth/register
router.post("/register", (req, res) => {
  const { username, email, password } = req.body;

  if (!username || !email || !password) {
    res.status(400).json({ error: "username, email, and password are required" });
    return;
  }

  const existing = users.find((u) => u.username === username);
  if (existing) {
    res.status(409).json({ error: "Username already taken" });
    return;
  }

  const newUser = {
    id: nextId(users),
    username,
    email,
    password, // plaintext per test expectations
  };
  users.push(newUser);

  const payload: JwtPayload = { userId: newUser.id, username: newUser.username };
  const token = jwt.sign(payload, JWT_SECRET);

  // Return user without the password field
  const { password: _pw, ...userWithoutPassword } = newUser;
  res.status(201).json({ token, user: userWithoutPassword });
});

// POST /auth/login
router.post("/login", (req, res) => {
  const { username, password } = req.body;

  const user = users.find((u) => u.username === username);
  if (!user || user.password !== password) {
    res.status(401).json({ error: "Invalid credentials" });
    return;
  }

  const payload: JwtPayload = { userId: user.id, username: user.username };
  const token = jwt.sign(payload, JWT_SECRET);

  res.status(200).json({ token });
});

export { router as authRouter };
```

Key decisions:
- Both missing-user and wrong-password cases return the same 401 to avoid username enumeration, which also matches the test's single-401 expectation for both cases.
- Object-rest destructuring `{ password: _pw, ...userWithoutPassword }` strips the password without mutating the stored record.
- No `expiresIn` is set on `jwt.sign`. The tests never check expiry and adding it would require the tests to be time-sensitive.

---

### Step 4 — `src/app.ts` (modify)

Add two lines: one import and one `app.use` registration.

```ts
