  const { title, content } = req.body;
  ...
  userId: req.user!.userId,
```

Key diff for PUT/DELETE (ownership check goes after 404 check):
```ts
router.put("/:id", authenticate, (req, res) => {
  ...
  if (index === -1) { res.status(404)... return; }
