import { Router } from "express";
import { posts, nextId } from "../db.js";
import { Post } from "../types.js";
import { authenticate } from "../middleware/auth.js";

const router = Router();

// GET /posts — public
router.get("/", (req, res) => {
  res.json(posts);
});

// GET /posts/:id — public
router.get("/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const post = posts.find((p) => p.id === id);
  if (!post) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  res.json(post);
});

// POST /posts — protected: requires valid JWT
router.post("/", authenticate, (req, res) => {
  const { title, content } = req.body;
  if (!title || !content) {
    res.status(400).json({ error: "title and content are required" });
    return;
  }
  const newPost: Post = {
    id: nextId(posts),
    title,
    content,
    userId: req.user!.userId, // sourced from JWT, never from request body
    createdAt: new Date().toISOString(),
  };
  posts.push(newPost);
  res.status(201).json(newPost);
});

// PUT /posts/:id — protected: requires valid JWT and ownership
router.put("/:id", authenticate, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  if (posts[index].userId !== req.user!.userId) {
    res.status(403).json({ error: "Forbidden" });
    return;
  }
  const { title, content } = req.body;
  if (title) posts[index].title = title;
  if (content) posts[index].content = content;
  res.json(posts[index]);
});

// DELETE /posts/:id — protected: requires valid JWT and ownership
router.delete("/:id", authenticate, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  if (posts[index].userId !== req.user!.userId) {
    res.status(403).json({ error: "Forbidden" });
    return;
  }
  const deleted = posts.splice(index, 1);
  res.json(deleted[0]);
});

export { router as postsRouter };

